package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import com.google.gson.Gson;
import com.google.gson.GsonBuilder;
import java.lang.reflect.Method;

class GsonTest {

  @Test
  void testNewBuilder() throws Exception {
    Gson gson = new Gson();

    // Direct call test
    GsonBuilder builder = gson.newBuilder();
    assertNotNull(builder);
    // The builder should be initialized with the Gson instance passed
    // Use reflection to access the private field 'gson' inside GsonBuilder to verify
    Method getGsonField = GsonBuilder.class.getDeclaredMethod("getGson");
    getGsonField.setAccessible(true);
    Gson internalGson = (Gson) getGsonField.invoke(builder);
    assertSame(gson, internalGson);

    // Additionally, test invoking newBuilder via reflection
    Method newBuilderMethod = Gson.class.getDeclaredMethod("newBuilder");
    newBuilderMethod.setAccessible(true);
    Object result = newBuilderMethod.invoke(gson);
    assertTrue(result instanceof GsonBuilder);
    assertSame(builder.getClass(), result.getClass());
  }
}
